import collections

def minTransfers(transactions: list[list[str]]) -> int:
    balance_map = collections.defaultdict(int)
    for giver, receiver, amount in transactions:
        balance_map[giver] -= amount
        balance_map[receiver] += amount

    balances_list = [balance for balance in balance_map.values() if balance != 0]

    def _solve(balances, k) -> int:
        while k < len(balances) and balances[k] == 0:
            k += 1

        if k == len(balances):
            return 0

        min_transactions = float('inf')

        for i in range(k + 1, len(balances)):
            if balances[k] * balances[i] < 0:

                original_balance_k = balances[k]
                original_balance_i = balances[i]

                transfer_amount = min(abs(original_balance_k), abs(original_balance_i))

                if original_balance_k < 0:
                    balances[k] += transfer_amount
                    balances[i] -= transfer_amount
                else:
                    balances[k] -= transfer_amount
                    balances[i] += transfer_amount

                transactions_needed = 1 + _solve(balances, k)
                min_transactions = min(min_transactions, transactions_needed)

                balances[k] = original_balance_k
                balances[i] = original_balance_i

        return min_transactions

    return _solve(balances_list, 0)
